package com.aiprovider.service;
import com.aiprovider.model.dto.ComfyTaskRecordDTO; import com.aiprovider.repository.ComfyTaskRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class ComfyTaskService { private final ComfyTaskRepository repository; public ComfyTaskService(ComfyTaskRepository r){repository=r;} public void save(ComfyTaskRecordDTO dto){ if(dto==null||blank(dto.getPromptId())||blank(dto.getWorkflowId())) throw new IllegalArgumentException("任务 ID 和工作流不能为空"); if(blank(dto.getWorkflowName())) dto.setWorkflowName(dto.getWorkflowId()); if(blank(dto.getParametersJson())) dto.setParametersJson("{}"); if(blank(dto.getStatus())) dto.setStatus("QUEUED"); repository.save(dto); } public Map<String,Object> duplicate(String workflowId,String hash){ if(blank(workflowId)||hash==null||!hash.matches("[0-9a-fA-F]{64}")) throw new IllegalArgumentException("工作流和 SHA-256 无效"); Map<String,Object> row=repository.findDuplicate(workflowId,hash.toLowerCase(Locale.ROOT)); return row==null?Collections.emptyMap():row; } public void complete(String id,List<String> paths){ if(blank(id)) throw new IllegalArgumentException("任务 ID 不能为空"); List<String> clean=paths==null?Collections.emptyList():paths.stream().filter(x->!blank(x)).toList(); String json="["+clean.stream().map(x->"\""+x.replace("\\","\\\\").replace("\"","\\\"")+"\"").reduce((a,b)->a+","+b).orElse("")+"]"; repository.complete(id,clean.isEmpty()?null:clean.get(0),json); } private static boolean blank(String v){return v==null||v.trim().isEmpty();} }
